import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const g=JSON.parse('{"title":"资本家","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/2.社交类/资本家.md","filePath":"4.资源分区/1.血统与训练/2.社交类/资本家.md"}'),s={name:"4.资源分区/1.血统与训练/2.社交类/资本家.md"};function d(o,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"资本家",tabindex:"-1"},[p("资本家 "),r("a",{class:"header-anchor",href:"#资本家","aria-label":'Permalink to "资本家"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风029")])])],-1),n('<h1 id="资本家-1" tabindex="-1">资本家 <a class="header-anchor" href="#资本家-1" aria-label="Permalink to &quot;资本家&quot;">​</a></h1><p>资本家</p><p>当利润达到10%时，便有人蠢蠢欲动；当利润达到50%的时候，有人敢于铤而走险；当利润达到100%时，他们敢于践踏人间一切法律；而当利润达到300%时，甚至连上绞刑架都豪不畏惧。<br> 你好，我们是“有人”</p><p>原始积累<br> D+600<br> 进行合法的商业投机、冒险贸易也好，进行灰色或罪恶的走私、欺诈也好，从其他人手中掠夺到第一笔资金，积累财富，这是资本家罪恶的基石。<br> 我的双手一尘不染：你只需要用自由动作打一个响指，就能在你的身边召唤一个如同保镖的黑色人影，你可以指挥他做任何你能做到的事情，但这个黑色的人影其实只是本体的延伸，并非随从，无法触碰到你触碰不到的事物，也无法离开你独自行动，举例来说你可以让其将你的触及范围内的水杯拿给你，但无法拿到你触及范围外的水杯。本质上黑色人影的一切行动都是你的行动，消耗你的动作，只是表现为你让背后的人影去做，一切使用你自身的数据进行检定，因此黑影也具有你自己的能力。对黑色人影进行攻击与对你进行攻击是一样的。你可以将武器交给黑色人影使用，这如同你自己装备了武器，占据相应的武器位。此外，你可以在购买时选择以下一个效果获得：<br> 1&gt;黑手：你起源于一些黑色生意，对于有些事情你非常熟练。当你或你的黑影进行枪械射击时，可以用操控+社交+专业：驱使+辅助专业：资本理论（学识下属）进行使用体积不超过2的手枪进行射击检定。<br> 2&gt;公务：你起源于一些权钱交易，地位是你的基石，你的社交相关检定获得1点内在加值<br> 3&gt;商人：你通过各种手段获取更多的财产，获得该能力后每当你进入影片都会获得相当于当前世界的75分等值货币，若影片结束后仍有剩余，则可以积累到下一个影片转化为该世界的等值货币。<br> 【原始积累】：在影片开始时你需要选择以下一种方式作为你的原始积累方案<br> 1&gt;商业投机，将至少价值1分的金钱或等价物作为素材进行商业投机，进行一次d2判定，若为1，则素材消失，投资失败，若为2，则你在当前影片完成原始积累方案，若素材足够，你可以进行任意次尝试，直到你完成原始积累方案。<br> 2&gt;血腥掠夺，每场获得胜利的战斗结束时，你可以进行一次d3检定，若出值不大于（1+当前影片中你之前进行该检定次数），则你完成原始积累方案。<br> 3&gt;快钱生意，若你在影片中获得价值10分及以上的金钱或等价物（即使是因为原始积累-商人等自身能力获得），则你完成原始积累方案<br> 若你在一场影片中完成了你选择的原始积累方案，则你在影片结束时，根据完成的影片次数依次获得人脉积累、信息积累、财富积累。<br> 1&gt;人脉积累：拥有人脉的你总能给人良好的印象，NPC对你的初始好感提升一级，至多为友善<br> 2&gt;信息积累：你知道了不为人知的事情，你获得【灵感视觉】，你的肉体与你使用操控属性进行的攻击获得【法破】<br> 3&gt;财富积累：你买下了一些空气、食物与药品，直接供应于身体中，你与贱民不再是相同的生物。你获得【无需呼吸】【无需饮食】【无需休息】<br> 资本积累：在你完成人脉积累、信息积累、财富积累后，你就有了一定的资本，你的操控相关检定获得2附加成功</p><p>资本扩张<br> C+1200<br> 在积累了一定的初始资本后，我们开始将资金投入到更广泛的领域，进行大规模的商业扩张。<br> 【上流人士】：当你进入影片时，若这个世界具有可流通的金钱这一概念，主神将为你随机安排一个具有小额资产的背景身份，这一身份可能是破落的农场主、小规模手工作坊老板、经营不善的外贸公司或是行商等。这是一个C级别、命运来源的背景身份。<br> 【资本循环】：你拥有生成资料，若你没有在进行资本循环，则你可以在主神空间宣称使用生产资料进行一轮资本循环，进入购买阶段，在开始循环后的第一场影片结束时，购买阶段结束，进入生产阶段，此时你可以支付750分加大生产，在第二场影片结束时出卖阶段结束，一轮资本循环完成，你积累一定资本，这让你的操控相关检定获得2附加成功，若你进行了加大生产，则额外获得1操控相关检定的附加成功，一轮资本循环完成后你可以立刻进行下一轮资本循环。然而我们仁慈且优秀的罗斯福主神抽取了90%的税，所以原本应该可以资本扩张让下一次资本循环获得更多收益的你无法扩大生产了。<br> 【注：以上特性的意思是，以两场影片为一周期，第一场影片结束时可以额外支付750分，接着在第二场影片结束时一并获得3点操控检定上的附加成功加值。（若不支付则仅2点附加成功）】</p><p>金融掌控<br> B+2400<br> 当资本积累到一定程度后，我们开始涉足金融领域，通过掌控银行、证券、保险等金融机构，掌握金融资源的分配和流动。<br> 【雄厚资本】：凭借资本的力量现在你已经有了强大的经济影响力，这代表你左右他人的能力达到一定程度，你的操控相关检定获得8加骰。<br> 【金钱异化】：一切都可以买到，于是过去的人文道德都被踩在脚下，剥削者反而被作为榜样敬畏，被你的攻击命中的敌人需要额外进行一次意志豁免对抗伤害出目，若失败，则当前场景下对方会尽可能避免对你进行攻击，即使被你进行攻击，不得不承认，赞扬剥削者的被剥削者还是不少的。这是一个心灵来源的B级支配效果。<br> 【左右经济】：<br> 说明：凭借对金融游戏的掌控你可以自如左右经济。这是一个B级、信息来源的模因效果。<br> 启动方式：只需要想着改变经济的方案，然后打个响指，你的身后就会飞出数个小黑影离开，他们会伪装成人来传递消息，制造一些事端来影响市场。<br> 作用范围：至多为一个城市<br> 起效时间：一般为1天后生效，城市过大，政府清明等原因可能导致这个时间延长。<br> 作用：一般可以起到以下三种作用<br> 1、让某类商品的售价上涨或下调至多10%，或让某类商品的市场存量减少或增加20%<br> 2、让某个店铺、超市获得暂时的好名声和坏名声，导致客流量上升或下降20%<br> 3、影响市民的消费欲望，减少或增加市民10%的消费，相应的改变银行存款的数额。<br> 持续时间：约一天，但并不意味着一天后效果就会完全消失，一天只是最短生效时间。<br> 后续影响：在一天后，效果可能继续存在，效果可能加剧，也可能减缓以至于消失，这取决于其他因素，比如在节假日等消费高峰选择效果“让消费欲望下降”，持续时间结束后由于仍然在节假日这一客观条件，所以效果会很快消失。操控粮价导致政府干预，这些也会让效果极快消失。相反的，若本来就是旅游消费高峰，并选择效果是“增加消费欲望”，则持续时间结束后这个影响很可能继续生效，甚至加剧。<br> 反复使用：反复使用同一个效果，比如连续让一个商品售价上涨，且没有价格上涨的客观条件，则效果会逐渐变弱直至没有，这意味着你还不能大幅度改变市场环境，应当顺势而为。<br> 资本联合：特殊的，若能和剧本内具有极大权利或极大资本的人合作，则在ST允许的情况下，可以让操控经济的效果强化。</p><p>权力渗透<br> A+4800<br> 在金融领域站稳脚跟后，开始将影响力渗透到政治领域。<br> 不可言说的大手：现在的你能够做到的事情自然不是贱民可比，当他们还在金钱游戏求生时，你随手就能掀起波浪，你获得8AP，只能用于使用操控属性进行的攻击检定。此外你的操控相关检定获得2附加成功。<br> 【跨界巨头】：当你进入影片时，你会获得一套身份证件与其他的身份证明，你至少应当拥有一所大型企业的全部股份，虽然这可能不是最顶级的一批超级企业，并且交给你雇佣的经纪人打理，你无需操心，拥有应有的财产。你拥有这个世界的记忆，你的公司通过宣传将你的能力解释为公司新产品，并且通过权钱交易让你的能力可以在公共场合合法使用（你可以使用你的能力，这不会惊扰其他人，但使用自己的能力去违法犯罪还是会遭遇官方逮捕），你与当地政府人士相识，也可以向你的经纪人了解一些干脏活的人士。这是一个A级背景身份。<br> 【权力投资】：从现在开始，你开始进行权利投资，从某个世界扶持自己的合作伙伴，以获取权利影响力。在购买该能力的第一场影片结束时，你必须支付1000分在拉票阶段投资你的合作伙伴，第二场影片结束时在最后的选举阶段支付1000分加大投资，这样在你的第三场影片开始前，你能得到来自合作伙伴的反馈，被该政府的全部国民祝福保护，获得【政治庇护】特性，毕竟，你的存在才能让他的权益稳固，你的存在才能让他们的市场平稳，他们自然会“衷心”地为你贡献力量。<br> 【政治庇护】：每轮一次，你可以调用合作世界的政府力量来保护自己，完全无效一次攻击，这是一个A级别祝福来源的无敌能力</p><p>专长 上流人士（1-2）<br> 1级：在上者<br> 占据了上流地位的你在社交中有更高的话语权，你的社交相关检定获得专长等级*1的增强加值<br> 2级：上流生活<br> 你可以在任何时候进行上流的生活，这表现为你可以在任何时候从手中生成一杯顶级茶水品尝，或是随处生成一个华丽的椅子坐下，但这只是一个D级幻象，所以没有实际的帮助，比如引用茶水也不能解渴，当然，你可以生成其他用来体现上流生活的物品，这仍然只是幻象，你的幻象可以持续任意时间，但脱离你的触及范围就会消失，在战斗中这是一个自由动作。在使用上流生活期间，若为非战斗状态，你的社交检定获得传奇操控*1的增强加值，若为战斗状态，只要你生成的幻象存在，你的黑影保镖进行的社交相关检定获得传奇操控*1的增强加值。这意味着可以表现为在你优雅且满不在乎的品尝昂贵的饮食时你身后的黑影举枪射击你的敌人，在你的敌人倒下时，你只是在享受自己的上流生活，双手一尘不染。</p><p>上等艺术（1-2）<br> 1级：这才是艺术<br> 这才是艺术。刚刚卖出艺术品赚了一大笔钱的我如是说。购买该专长后的下一个影片的第一天结束时，因为你命手下在当前时间进行的艺术活动你会获得价值150分的当前世界金钱，若影片结束时这些金钱没有被花光，则自动积累并在进入下一个影片时转化为相应的货币，此后的每个影片第一天结束时你都会收到价值150分的货币，若影片内时间不足一天，你会在影片结束后在主神空间收到属下给你的150分金钱。<br> 2级：没有什么比这更艺术了<br> 你可以对你的操控属性相关的攻击检定进行任意的留手，在进行攻击后，进行完这次攻击所有附带效果的对抗后，你可以选择令这次攻击不对对方产生生命值损伤。欣赏被你影响之人的丑态，这才是最好的娱乐。你进行附带需要意志豁免的异常状态或异常点数的攻击时获得1附加成功。</p><p>资本网络（1-2）<br> 1级：肮脏同盟<br> 借助你的人际分担你的苦难，你获得等同于当前场景友方人数*1的偏斜防御，上限为专长等级。<br> 2级：基金网络<br> 你可以随时生成一张烫金名片（你可以设置名片上的信息，也可以是虚假的信息），将其交给任何人，你与持有名片的人可以无视距离地进行语音交流，若你或对方有电脑等设备，则你们可以借助名片传输图片、文字、视频等。这是一个D级信息共享效果。此外，你建立了一个基金会用来隐藏你的非法账目与非法物品，你可以在任何地方在基金会中存取物品，基金会为你准备的空间容量为10立方米，不能装独立单位、放入/取出物品至少是一个迅捷动作，这是一个D级储存空间。进行存取时表现为在空中产生一个金色的圆形（半径约10cm，根据你需要存取的物品大小可以变大）的小型传送门，将需要存取的物品吐出或存入。</p><p>-------------手段（下属技艺）----------------<br> 通用：<br> 基本盘<br> C+1000<br> 良好的基本盘是扩张的基础，和当地的一切打通关节，至少成为XX必胜客，这会很有帮助。<br> 你在自己周围构建了严密的壁垒，严阵以待。<br> 若你拥有“教父”手枪，则你的枪械攻击不会因为自身在对方触及范围内导致高速减半。且若对方在你的触及范围内，你对其进行的枪械攻击获得【碾压】。<br> 若你拥有“饲主”手杖，则你的施法攻击不会因为自身在对方触及范围内导致高速减半。且若对方在你的触及范围内，你对其进行的施法攻击获得【碾压】。<br> 让对方感受你在这里令人绝望的关系网吧。<br> 特殊的，若你的“教父”或“饲主”等级在B级以上，则对方即使不在你的触及范围内你的攻击仍具有【碾压】</p><p>强压<br> B+2000<br> 动用各种关系，稍微突破一些限制，进行一次强烈的冲击，将那些对我不满的家伙强压下去。有效，但需要注意影响，若反复使用，会付出代价。<br> 一场景仅能使用一次，使用移动动作并支付3点意志，全力驱动你手中的“教父”手枪或“饲主”手杖，表现为大量黑气突然出现并萦绕其上，令你使用该武器进行的下一次攻击获得等同于你操控属性-1的附加成功。<br> 研发：40XP，升级为A技艺，获得相差的属性点。<br> 绝对强压，一场景仅能使用一次，使用移动动作并支付4点意志，全力驱动你手中的“教父”手枪或“饲主”手杖，表现为大量黑气突然出现并萦绕其上，令你使用该武器进行的下一次攻击获得等同于你操控属性-1的附加成功。且此次攻击伤害增加两倍。</p><p>闲棋<br> B+2000<br> 欲成大业，稳固的产业是必要的，但，在维持稳固的前提下，下一步可有可无的闲棋，期待在必要时能用以谋取利益，这也是必要的策略。<br> 稳固：通过稳定的产业徐徐图之，拥有“教父”手枪或“饲主”手杖时，每轮一次，你可以令操控属性相关检定重骰一次，取高值。<br> 投机：设下暗桩，押注未来，只需少量的付出，就可以期待得到丰厚的回报。你使用“教父”手枪或“饲主”手杖进行的枪械/施法攻击获得湮灭。</p><p>教父专属：<br> 联合通缉<br> B+2000<br> 对任意目标下达对于整个黑社会的通缉令，进行联合追击，令其无所遁形。<br> 攻击技艺，标准动作，支付1意志力使用，对射程内任意数量的敌人进行射击，在此次攻击命中后，对方需用反射豁免对抗伤害，若失败，则其在当前场景中被打上通缉标记，拥有通缉标记的单位在受到任何攻击时均视为被忽略闪避防御，这是一个B级别信息来源的效果。</p><p>饲主专属：<br> 地下根须<br> C+1000<br> 安插，收买，渗透，盘根错节，拥有一个复杂的情报网络。<br> 通过改进渗透网络，走狗传递的信息更为直观，你能从只有你能察觉的哪些黑影/白影中以他们给予的只有你能看见的照片与文字的形式得知感知范围内的任何画面与声音信息，这会令你的听觉感知方式提升为强感知，且这种感知方式具有【透视】，并且免疫耳聋异常点数带来的减值与严重状态</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',17)])])}const f=e(s,[["render",d]]);export{g as __pageData,f as default};
